+    public MemorySegment createStringTensor(Arena arena, String[] data, long[] shape) {
+        var allocatorInfo = retAddr(OrtApi.AllocatorGetInfo.invoke(OrtApi.AllocatorGetInfo(runtimeAddress), defaultAllocatorAddress, ret));
